import{_ as a,o as e,c as r,S as s}from"./chunks/framework.C6RQlTYc.js";const u=JSON.parse('{"title":"MCP 协议","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_27-mcp.md","filePath":"直击概念/17ai/s_ai_27-mcp.md","lastUpdated":1778207238000}'),l={name:"直击概念/17ai/s_ai_27-mcp.md"};function n(i,t,o,d,p,h){return e(),r("div",null,[...t[0]||(t[0]=[s(`<h1 id="mcp-协议" tabindex="-1">MCP 协议 <a class="header-anchor" href="#mcp-协议" aria-label="Permalink to &quot;MCP 协议&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>MCP（Model Context Protocol）是 Anthropic 于 2024 年发布的<strong>开源标准协议</strong>，为 AI 模型与外部工具、数据源之间的连接提供了一个统一的&quot;USB 接口&quot;。在此之前，每个 LLM 需要为每个外部工具编写专属的集成代码——MCP 的目标是让这种连接标准化、可复用。</p><p>简单理解：MCP 之于 AI，就像 HTTP 之于 Web、USB 之于外设——一个统一的协议让连接变得简单。</p><h2 id="核心概念" tabindex="-1">核心概念 <a class="header-anchor" href="#核心概念" aria-label="Permalink to &quot;核心概念&quot;">​</a></h2><h3 id="mcp-架构" tabindex="-1">MCP 架构 <a class="header-anchor" href="#mcp-架构" aria-label="Permalink to &quot;MCP 架构&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>┌──────────┐        MCP Protocol       ┌──────────┐</span></span>
<span class="line"><span>│  Client  │ ←────────────────────────→ │  Server  │</span></span>
<span class="line"><span>│ (Host)   │   JSON-RPC over stdio/SSE │          │</span></span>
<span class="line"><span>└──────────┘                            └──────────┘</span></span>
<span class="line"><span>     │                                      │</span></span>
<span class="line"><span> Claude / GPT /                        外部工具、API、</span></span>
<span class="line"><span>你的应用                               数据库、文件系统</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><ul><li><strong>Host（宿主）</strong>：运行 AI 模型的应用（Claude Desktop、VS Code、你的应用）</li><li><strong>Client（客户端）</strong>：Host 内部的协议客户端，管理与 Server 的连接</li><li><strong>Server（服务端）</strong>：暴露工具/资源/提示词的 MCP 服务</li></ul><h3 id="三种核心原语" tabindex="-1">三种核心原语 <a class="header-anchor" href="#三种核心原语" aria-label="Permalink to &quot;三种核心原语&quot;">​</a></h3><table><thead><tr><th>原语</th><th>用途</th><th>示例</th></tr></thead><tbody><tr><td><strong>Tools（工具）</strong></td><td>模型可调用的函数</td><td>查询数据库、搜索文件、发送邮件</td></tr><tr><td><strong>Resources（资源）</strong></td><td>模型可读取的数据</td><td>本地文件、知识库、API 响应</td></tr><tr><td><strong>Prompts（提示词）</strong></td><td>预定义的 prompt 模板</td><td>代码审查 prompt、翻译 prompt</td></tr></tbody></table><h2 id="与-a2a-的关系" tabindex="-1">与 A2A 的关系 <a class="header-anchor" href="#与-a2a-的关系" aria-label="Permalink to &quot;与 A2A 的关系&quot;">​</a></h2><p>Google 的 A2A（Agent-to-Agent）协议与 MCP 互补而非竞争：</p><table><thead><tr><th>维度</th><th>MCP</th><th>A2A</th></tr></thead><tbody><tr><td>目的</td><td>模型 ↔ 工具/数据</td><td>Agent ↔ Agent</td></tr><tr><td>层次</td><td>基础设施层</td><td>应用协作层</td></tr><tr><td>提出方</td><td>Anthropic</td><td>Google</td></tr><tr><td>角色</td><td>&quot;给 AI 装 USB 口&quot;</td><td>&quot;让 Agent 对讲&quot;</td></tr></tbody></table><h2 id="工作方式" tabindex="-1">工作方式 <a class="header-anchor" href="#工作方式" aria-label="Permalink to &quot;工作方式&quot;">​</a></h2><h3 id="json-rpc-通信" tabindex="-1">JSON-RPC 通信 <a class="header-anchor" href="#json-rpc-通信" aria-label="Permalink to &quot;JSON-RPC 通信&quot;">​</a></h3><p>MCP 基于 JSON-RPC 2.0，支持两种传输方式：</p><ul><li><strong>标准输入/输出（stdio）</strong>：本地进程间通信</li><li><strong>Server-Sent Events（SSE）</strong>：远程 HTTP 通信</li></ul><h3 id="生命周期" tabindex="-1">生命周期 <a class="header-anchor" href="#生命周期" aria-label="Permalink to &quot;生命周期&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0"><code><span class="line"><span>初始化 → 能力协商 → 工具/资源发现 → 模型调用工具 → 返回结果</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><ol><li>Client 向 Server 请求可用工具列表</li><li>Host 将工具列表注册到 LLM 的可用工具中</li><li>用户提问 → LLM 决定调用某个 MCP 工具</li><li>Client 转发调用给 Server → Server 执行并返回结果</li><li>LLM 结合结果生成最终回答</li></ol><h2 id="对前端开发者的意义" tabindex="-1">对前端开发者的意义 <a class="header-anchor" href="#对前端开发者的意义" aria-label="Permalink to &quot;对前端开发者的意义&quot;">​</a></h2><h3 id="为什么需要关注" tabindex="-1">为什么需要关注 <a class="header-anchor" href="#为什么需要关注" aria-label="Permalink to &quot;为什么需要关注&quot;">​</a></h3><ul><li><strong>连接任意数据源</strong>：通过 MCP Server 将数据库、API、文件系统暴露给 AI</li><li><strong>一站式集成</strong>：不再为每个 LLM 单独写集成代码</li><li><strong>社区生态</strong>：已有数百个开源 MCP Server（Puppeteer、GitHub、Postgres、Filesystem 等）</li><li><strong>Claude Code / Cursor 支持</strong>：主流 AI 编程工具已集成 MCP</li></ul><h3 id="前端相关-mcp-server-示例" tabindex="-1">前端相关 MCP Server 示例 <a class="header-anchor" href="#前端相关-mcp-server-示例" aria-label="Permalink to &quot;前端相关 MCP Server 示例&quot;">​</a></h3><ul><li><strong>Browser MCP</strong>：让 AI 操作浏览器</li><li><strong>Figma MCP</strong>：连接设计稿</li><li><strong>Filesystem MCP</strong>：读写本地文件</li><li><strong>GitHub MCP</strong>：操作 GitHub 仓库</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>MCP 解决了什么问题？和 Function Calling 有什么关系？</li><li>MCP 和 A2A 的区别与应用场景？</li><li>作为前端开发者，你如何使用 MCP 来增强开发效率？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://modelcontextprotocol.io/" target="_blank" rel="noreferrer">Model Context Protocol Specification</a></li><li><a href="https://github.com/modelcontextprotocol/typescript-sdk" target="_blank" rel="noreferrer">MCP TypeScript SDK</a></li><li><a href="https://developers.googleblog.com/en/a2a-a-new-era-of-agent-interoperability/" target="_blank" rel="noreferrer">A2A Protocol - Google</a></li></ul>`,29)])])}const b=a(l,[["render",n]]);export{u as __pageData,b as default};
